require(['jquery'], $ => {
  'use strict';
  $(() => {
    const form = document.getElementById('mcp-server-config');
    if (!form) {
      return;
    }
    const treeElement = document.getElementById('mcp-space-picker-tree');
    if (!treeElement) {
      return;
    }

    const spaceList = $('#mcp-space-chips');
    const docList = $('#mcp-doc-chips');

    // The endpoint's own wiki id, carried on the picker container. Chips for this wiki are stored unqualified.
    const currentWiki = $('.mcp-space-picker').attr('data-current-wiki');

    // node.data.id is the wiki-prefixed serialized reference (e.g. "xwiki:Space.Page"). A chip for the current wiki
    // is stored unqualified (drop the wiki prefix); a chip for any other wiki keeps its "<wiki>:<localRef>" form so
    // the stored entry stays wiki-qualified and is interpreted against that other wiki.
    const chipRef = rawId => {
      const separatorIndex = rawId.indexOf(':');
      if (separatorIndex < 0) {
        return rawId;
      }
      const wiki = rawId.substring(0, separatorIndex);
      return wiki === currentWiki ? rawId.substring(separatorIndex + 1) : rawId;
    };

    const listValues = list =>
      list.find('.mcp-chip input[type="hidden"]').map((index, input) => input.value).get();

    const refreshEmpty = list => {
      list.find('.mcp-chip-empty').toggle(list.find('.mcp-chip').length === 0);
    };

    const chipExists = (list, value) => listValues(list).includes(value);

    const addChip = (list, inputClass, value) => {
      if (chipExists(list, value)) {
        return;
      }
      const fieldName = list.data('field');
      const removeLabel = list.data('remove-label') || 'Remove';
      const chip = $('<span class="mcp-chip"></span>');
      $('<span class="mcp-chip-label"></span>').text(value).appendTo(chip);
      $('<button type="button" class="mcp-chip-remove"></button>')
        .attr('aria-label', `${removeLabel} ${value}`).text('×').appendTo(chip);
      $('<input type="hidden" />').attr('name', fieldName).addClass(inputClass).val(value).appendTo(chip);
      list.find('.mcp-chip-empty').before(chip);
      refreshEmpty(list);
    };

    const removeChipByValue = (list, value) => {
      list.find('.mcp-chip input[type="hidden"]').each((index, input) => {
        if (input.value === value) {
          $(input).closest('.mcp-chip').remove();
        }
      });
      refreshEmpty(list);
    };

    // A space reference covers itself and its whole subtree, so it "covers" any document or sub-space reference
    // prefixed by "<space>." — the trailing dot prevents "Sand" from matching "Sandbox".
    const coversRef = (spaceRef, ref) => ref === spaceRef || ref.startsWith(`${spaceRef}.`);

    // Remove every chip in the list whose reference is covered by (but not equal to) the given space reference.
    const removeCovered = (list, spaceRef) => {
      listValues(list)
        .filter(value => value !== spaceRef && coversRef(spaceRef, value))
        .forEach(value => removeChipByValue(list, value));
    };

    const isCoveredByExistingSpace = ref => listValues(spaceList).some(spaceRef => coversRef(spaceRef, ref));

    const addNodeChip = node => {
      if (!node || !node.data || !node.data.id) {
        return;
      }
      const ref = chipRef(node.data.id);
      if (node.data.type === 'space') {
        // A whole subtree collapses to a single space chip: drop any document or sub-space chip it now covers.
        removeCovered(spaceList, ref);
        removeCovered(docList, ref);
        addChip(spaceList, 'mcp-space-chip-input', ref);
      } else if (node.data.type === 'document' && !isCoveredByExistingSpace(ref)) {
        // A document already covered by a space chip is skipped (redundant with the subtree the space stands for).
        addChip(docList, 'mcp-doc-chip-input', ref);
      }
    };

    const removeNodeChip = node => {
      if (!node || !node.data || !node.data.id) {
        return;
      }
      const ref = chipRef(node.data.id);
      if (node.data.type === 'space') {
        removeChipByValue(spaceList, ref);
      } else if (node.data.type === 'document') {
        removeChipByValue(docList, ref);
      }
    };

    // Navigation is suppressed at the source by the documentTree macro's links="false" option (set in the sheet).

    // The checkbox plugin keeps its jsTree defaults (three_state cascade, tie_selection), so checking a space also
    // checks its descendants. jsTree's core 'changed' event carries the full selection (data.selected) but not the
    // per-change delta (that lives in the optional 'changed' plugin, which is not loaded), so on every change we
    // recompute the "top selected" set — selected nodes whose parent is not also selected — and reconcile the chips to
    // it. A checked sub-tree therefore collapses to its single top node (one space chip), mirroring the export tree;
    // and when a sub-page is unchecked the space drops back to individual chips for the pages that stay checked.
    // Stored chips are never in the tree selection, so this pass leaves them untouched unless the tree covers them.
    let chippedNodes = [];
    $(treeElement).on('changed.jstree', (event, data) => {
      const tree = data.instance;
      if (data.action === 'deselect_all') {
        // The tree finder (finder.js) deselects everything before selecting its result, which would otherwise
        // wipe every existing chip. Re-apply the committed selection so a finder pick ADDS to the chips instead
        // of replacing them; this picker exposes no other deselect-all action.
        if (chippedNodes.length) {
          tree.select_node(chippedNodes);
        }
        return;
      }
      const current = data.selected || [];
      const currentSet = new Set(current);
      const isWiki = nodeId => {
        const node = tree.get_node(nodeId);
        return !!(node && node.data && node.data.type === 'wiki');
      };
      const topSelected = current.filter(nodeId => {
        if (isWiki(nodeId)) {
          return false;
        }
        const node = tree.get_node(nodeId);
        if (!node) {
          return false;
        }
        const parent = node.parent;
        // Top-selected = has no selected non-wiki ancestor directly above it. A selected wiki parent does not
        // "cover" its spaces (wikis are not chips), so a space under a checked wiki is itself top-selected.
        return !(parent && currentSet.has(parent) && !isWiki(parent));
      });
      const topSet = new Set(topSelected);
      // Drop chips for nodes no longer top-selected first, then add chips for the newly top-selected ones.
      chippedNodes
        .filter(nodeId => !topSet.has(nodeId))
        .forEach(nodeId => removeNodeChip(tree.get_node(nodeId)));
      topSelected
        .filter(nodeId => !chippedNodes.includes(nodeId))
        .forEach(nodeId => addNodeChip(tree.get_node(nodeId)));
      chippedNodes = topSelected;
    });

    $(form).on('click', '.mcp-chip-remove', event => {
      const target = $(event.currentTarget);
      const list = target.closest('.mcp-chip-list');
      target.closest('.mcp-chip').remove();
      refreshEmpty(list);
    });

    // On load the saved configuration is rendered as chips but the lazily-loaded tree starts unchecked. Re-check the
    // stored references so the tree reflects the saved state. The node id is "<type>:<serialized reference>" where the
    // serialized reference is wiki-prefixed (e.g. "space:xwiki:Sandbox", "document:second:Sandbox.WebHome"); a stored
    // ref is already wiki-qualified for other wikis and unqualified for the current wiki, so we qualify with the
    // current wiki only when needed and rebuild the ids. openTo lazily loads the path to each node and selects it,
    // which feeds back through the changed handler above where the chipExists dedup keeps it from duplicating the
    // server-rendered chips. This runs once, when ready.
    const preselectStoredReferences = tree => {
      if (!currentWiki) {
        return;
      }
      // A stored ref is wiki-qualified when it contains a ':' (e.g. "second:Sandbox"); an unqualified ref
      // (e.g. "Sandbox" or "Sandbox.WebHome") belongs to the current wiki.
      const qualify = ref => ref.indexOf(':') >= 0 ? ref : `${currentWiki}:${ref}`;
      const nodeIds = [
        ...listValues(spaceList).map(ref => `space:${qualify(ref)}`),
        ...listValues(docList).map(ref => `document:${qualify(ref)}`)
      ];
      if (nodeIds.length) {
        tree.openTo(nodeIds);
      }
    };

    let preselected = false;
    const runPreselect = () => {
      if (preselected) {
        return;
      }
      if (!$.jstree) {
        return;
      }
      const tree = $.jstree.reference(treeElement);
      if (!tree || !tree._data || !tree._data.core || !tree._data.core.ready) {
        return;
      }
      preselected = true;
      preselectStoredReferences(tree);
    };
    $(treeElement).on('ready.jstree', runPreselect);
    runPreselect();

    refreshEmpty(spaceList);
    refreshEmpty(docList);
  });
});
